// ChartCard.jsx — Chart with "Explain this chart" voice button

import { useState, useRef } from "react";
import {
  BarChart, Bar, LineChart, Line, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend,
  ResponsiveContainer, AreaChart, Area
} from "recharts";

const COLOR_PALETTES = {
  default: ["#4f8ef7", "#7c5cfc", "#00d4aa", "#f7a84f", "#f75959", "#e879f9"],
  blue:    ["#0ea5e9", "#38bdf8", "#7dd3fc", "#bae6fd", "#0284c7", "#0369a1"],
  warm:    ["#f97316", "#fb923c", "#fbbf24", "#f43f5e", "#e11d48", "#c2410c"],
  dark:    ["#a78bfa", "#34d399", "#fb7185", "#fbbf24", "#60a5fa", "#f472b6"],
};

const fmt = (val) => {
  if (typeof val !== "number") return val;
  if (val >= 1_000_000) return `${(val / 1_000_000).toFixed(1)} million`;
  if (val >= 1_000) return `${(val / 1_000).toFixed(1)} thousand`;
  return Number.isInteger(val) ? val : parseFloat(val.toFixed(2));
};

const fmtDisplay = (val) => {
  if (typeof val !== "number") return val;
  if (val >= 1_000_000) return `${(val / 1_000_000).toFixed(1)}M`;
  if (val >= 1_000) return `${(val / 1_000).toFixed(1)}K`;
  return Number.isInteger(val) ? val : val.toFixed(2);
};

// ── Build a plain-English explanation of the chart data ──────────────────────
function buildExplanation(chart) {
  const data = chart.data || [];
  const xKey = chart.x_axis;
  const title = chart.title;
  const chartType = chart.chart_type;

  if (!data.length) return `This chart titled "${title}" has no data to explain.`;

  // Find numeric value keys
  const valueKeys = Object.keys(data[0]).filter((k) => k !== xKey && typeof data[0][k] === "number");
  if (!valueKeys.length) return `This chart shows ${title}.`;

  const mainKey = valueKeys[0];

  // Sort by value to find top and bottom
  const sorted = [...data].sort((a, b) => (b[mainKey] || 0) - (a[mainKey] || 0));
  const top = sorted[0];
  const bottom = sorted[sorted.length - 1];
  const total = data.reduce((sum, row) => sum + (row[mainKey] || 0), 0);
  const avg = total / data.length;

  let explanation = `This chart is about ${title}. `;

  // Chart-type specific intro
  if (chartType === "pie") {
    explanation += `It shows how ${mainKey} is distributed across different ${xKey}s. `;
  } else if (chartType === "line" || chartType === "area") {
    explanation += `It shows the trend of ${mainKey} over time. `;
  } else {
    explanation += `It compares ${mainKey} across different ${xKey}s. `;
  }

  // Top performer
  if (top && top[xKey] !== undefined) {
    explanation += `The highest value is ${fmt(top[mainKey])}, which belongs to ${top[xKey]}. `;
  }

  // Bottom performer
  if (bottom && bottom[xKey] !== undefined && bottom[xKey] !== top[xKey]) {
    explanation += `The lowest value is ${fmt(bottom[mainKey])}, which belongs to ${bottom[xKey]}. `;
  }

  // Total and average
  if (data.length > 2) {
    explanation += `The total across all entries is ${fmt(total)}, with an average of ${fmt(avg)}. `;
  }

  // Trend for line charts
  if ((chartType === "line" || chartType === "area") && data.length >= 2) {
    const first = data[0][mainKey];
    const last = data[data.length - 1][mainKey];
    const diff = last - first;
    const pct = first !== 0 ? Math.abs((diff / first) * 100).toFixed(1) : 0;
    if (diff > 0) {
      explanation += `Overall, there is an upward trend with an increase of ${pct} percent from start to end. `;
    } else if (diff < 0) {
      explanation += `Overall, there is a downward trend with a decrease of ${pct} percent from start to end. `;
    } else {
      explanation += `The values remain relatively stable overall. `;
    }
  }

  // Pie chart — top share
  if (chartType === "pie" && total > 0) {
    const topShare = ((top[mainKey] / total) * 100).toFixed(1);
    explanation += `${top[xKey]} makes up ${topShare} percent of the total. `;
  }

  explanation += `There are ${data.length} data points in this chart.`;
  return explanation;
}

// ── Speak using browser speech synthesis ────────────────────────────────────
function speakText(text, onStart, onEnd) {
  if (!window.speechSynthesis) {
    alert("Your browser does not support voice. Please use Chrome or Edge.");
    return;
  }
  // Cancel any ongoing speech first
  window.speechSynthesis.cancel();

  const utterance = new SpeechSynthesisUtterance(text);
  utterance.rate = 0.88;       // slightly slow for clarity
  utterance.pitch = 1.0;
  utterance.volume = 1.0;

  // Try to pick a natural English voice
  const voices = window.speechSynthesis.getVoices();
  const preferred = voices.find(
    (v) => v.lang.startsWith("en") && (v.name.includes("Google") || v.name.includes("Natural") || v.name.includes("Samantha"))
  ) || voices.find((v) => v.lang.startsWith("en"));
  if (preferred) utterance.voice = preferred;

  utterance.onstart = onStart;
  utterance.onend = onEnd;
  utterance.onerror = onEnd;

  window.speechSynthesis.speak(utterance);
}

// ── Custom Tooltip ───────────────────────────────────────────────────────────
const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={ttStyles.box}>
      <p style={ttStyles.label}>{label}</p>
      {payload.map((p, i) => (
        <p key={i} style={{ ...ttStyles.val, color: p.color }}>
          {p.name}: <strong>{fmtDisplay(p.value)}</strong>
        </p>
      ))}
    </div>
  );
};

const ttStyles = {
  box: { background: "#1a1f2e", border: "1px solid #2a3040", borderRadius: "10px", padding: "10px 14px", boxShadow: "0 8px 24px rgba(0,0,0,0.4)" },
  label: { fontSize: "12px", color: "#8891a8", marginBottom: "6px" },
  val: { fontSize: "13px", fontWeight: 500 },
};

// ── Main ChartCard Component ─────────────────────────────────────────────────
export default function ChartCard({ chart, colorSchema = "default", index = 0 }) {
  const [speaking, setSpeaking] = useState(false);
  const [showExplanation, setShowExplanation] = useState(false);
  const [explanation, setExplanation] = useState("");
  const colors = COLOR_PALETTES[colorSchema] || COLOR_PALETTES.default;
  const data = chart.data || [];
  const xKey = chart.x_axis;
  const yKey = chart.y_axis;

  const dataKeys = data.length > 0
    ? Object.keys(data[0]).filter((k) => k !== xKey)
    : [yKey];

  // ── Handle speak button click ─────────────────────────────────────────────
  const handleSpeak = () => {
    if (speaking) {
      window.speechSynthesis.cancel();
      setSpeaking(false);
      return;
    }
    const text = buildExplanation(chart);
    setExplanation(text);
    setShowExplanation(true);
    speakText(
      text,
      () => setSpeaking(true),
      () => setSpeaking(false)
    );
  };

  // ── Chart renderer ────────────────────────────────────────────────────────
  const renderChart = () => {
    switch (chart.chart_type) {
      case "line":
        return (
          <LineChart data={data}>
            <CartesianGrid strokeDasharray="3 3" stroke="#1e2333" />
            <XAxis dataKey={xKey} tick={{ fill: "#8891a8", fontSize: 11 }} axisLine={false} tickLine={false} />
            <YAxis tickFormatter={fmtDisplay} tick={{ fill: "#8891a8", fontSize: 11 }} axisLine={false} tickLine={false} />
            <Tooltip content={<CustomTooltip />} />
            <Legend wrapperStyle={{ fontSize: "12px" }} />
            {dataKeys.map((key, i) => (
              <Line key={key} type="monotone" dataKey={key} stroke={colors[i % colors.length]}
                strokeWidth={2.5} dot={{ r: 3, fill: colors[i % colors.length] }} activeDot={{ r: 5 }} />
            ))}
          </LineChart>
        );

      case "area":
        return (
          <AreaChart data={data}>
            <defs>
              {dataKeys.map((key, i) => (
                <linearGradient key={key} id={`grad-${index}-${i}`} x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor={colors[i % colors.length]} stopOpacity={0.3} />
                  <stop offset="95%" stopColor={colors[i % colors.length]} stopOpacity={0} />
                </linearGradient>
              ))}
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="#1e2333" />
            <XAxis dataKey={xKey} tick={{ fill: "#8891a8", fontSize: 11 }} axisLine={false} tickLine={false} />
            <YAxis tickFormatter={fmtDisplay} tick={{ fill: "#8891a8", fontSize: 11 }} axisLine={false} tickLine={false} />
            <Tooltip content={<CustomTooltip />} />
            {dataKeys.map((key, i) => (
              <Area key={key} type="monotone" dataKey={key}
                stroke={colors[i % colors.length]} strokeWidth={2}
                fill={`url(#grad-${index}-${i})`} />
            ))}
          </AreaChart>
        );

      case "pie":
        return (
          <PieChart>
            <Pie data={data} dataKey={dataKeys[0]} nameKey={xKey}
              cx="50%" cy="50%" outerRadius={90} innerRadius={40}
              paddingAngle={3} strokeWidth={0}>
              {data.map((_, i) => (
                <Cell key={i} fill={colors[i % colors.length]} />
              ))}
            </Pie>
            <Tooltip content={<CustomTooltip />} />
            <Legend wrapperStyle={{ fontSize: "12px" }} />
          </PieChart>
        );

      default: // bar
        return (
          <BarChart data={data} barCategoryGap="30%">
            <CartesianGrid strokeDasharray="3 3" stroke="#1e2333" vertical={false} />
            <XAxis dataKey={xKey} tick={{ fill: "#8891a8", fontSize: 11 }} axisLine={false} tickLine={false} />
            <YAxis tickFormatter={fmtDisplay} tick={{ fill: "#8891a8", fontSize: 11 }} axisLine={false} tickLine={false} />
            <Tooltip content={<CustomTooltip />} />
            <Legend wrapperStyle={{ fontSize: "12px" }} />
            {dataKeys.map((key, i) => (
              <Bar key={key} dataKey={key} fill={colors[i % colors.length]}
                radius={[4, 4, 0, 0]} maxBarSize={48} />
            ))}
          </BarChart>
        );
    }
  };

  return (
    <div style={{ ...styles.card, animationDelay: `${index * 0.1}s` }} className="fade-up">

      {/* ── Card Header ───────────────────────────────────────────────────── */}
      <div style={styles.cardHeader}>
        <div style={styles.titleRow}>
          <div style={{ ...styles.typeBadge, background: `${colors[0]}22`, color: colors[0] }}>
            {chart.chart_type}
          </div>
          <h3 style={styles.cardTitle}>{chart.title}</h3>
        </div>

        {/* Speak Button */}
        <button
          style={{ ...styles.speakBtn, ...(speaking ? styles.speakBtnActive : {}) }}
          onClick={handleSpeak}
          title={speaking ? "Stop explanation" : "Explain this chart in voice"}
        >
          {speaking ? (
            <>
              {/* Animated sound waves when speaking */}
              <div style={styles.waveWrap}>
                <span style={{ ...styles.wave, animationDelay: "0s" }} />
                <span style={{ ...styles.wave, animationDelay: "0.15s" }} />
                <span style={{ ...styles.wave, animationDelay: "0.3s" }} />
              </div>
              Stop
            </>
          ) : (
            <>
              {/* Speaker icon */}
              <svg width="14" height="14" viewBox="0 0 16 16" fill="none">
                <path d="M3 6H1v4h2l4 3V3L3 6z" fill="currentColor"/>
                <path d="M11.5 8a3.5 3.5 0 00-2-3.15v6.3A3.5 3.5 0 0011.5 8z" fill="currentColor"/>
                <path d="M14 8a6 6 0 00-3-5.2v1.56A4.5 4.5 0 0113 8a4.5 4.5 0 01-2 3.64v1.56A6 6 0 0014 8z" fill="currentColor"/>
              </svg>
              Explain
            </>
          )}
        </button>
      </div>

      {/* ── Chart ─────────────────────────────────────────────────────────── */}
      <div style={styles.chartWrap}>
        <ResponsiveContainer width="100%" height={240}>
          {renderChart()}
        </ResponsiveContainer>
      </div>

      {/* ── Explanation Text Box ──────────────────────────────────────────── */}
      {showExplanation && explanation && (
        <div style={styles.explanationBox}>
          <div style={styles.explanationHeader}>
            <div style={styles.explanationDot} />
            <span style={styles.explanationLabel}>
              {speaking ? "🔊 Speaking..." : "📋 Explanation"}
            </span>
            <button
              style={styles.closeExplanation}
              onClick={() => { setShowExplanation(false); window.speechSynthesis.cancel(); setSpeaking(false); }}
            >
              ✕
            </button>
          </div>
          <p style={styles.explanationText}>{explanation}</p>
        </div>
      )}
    </div>
  );
}

// ── Styles ───────────────────────────────────────────────────────────────────
const styles = {
  card: {
    background: "var(--bg2)",
    border: "1px solid var(--border)",
    borderRadius: "var(--radius-lg)",
    overflow: "hidden",
    transition: "border-color 0.2s",
  },
  cardHeader: {
    padding: "14px 16px 12px",
    borderBottom: "1px solid var(--border)",
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    gap: "10px",
  },
  titleRow: {
    display: "flex", alignItems: "center", gap: "10px", flex: 1, minWidth: 0,
  },
  typeBadge: {
    padding: "3px 10px", borderRadius: "20px",
    fontSize: "11px", fontWeight: 700,
    textTransform: "uppercase", letterSpacing: "0.05em",
    flexShrink: 0,
  },
  cardTitle: {
    fontSize: "14px", fontWeight: 700,
    color: "var(--text)", letterSpacing: "-0.2px",
    whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
  },

  // ── Speak button ─────────────────────────────────────────
  speakBtn: {
    display: "flex", alignItems: "center", gap: "6px",
    padding: "7px 14px",
    background: "rgba(79,142,247,0.1)",
    border: "1px solid rgba(79,142,247,0.25)",
    borderRadius: "20px",
    color: "var(--accent)",
    fontSize: "12px", fontWeight: 600,
    cursor: "pointer",
    flexShrink: 0,
    transition: "all 0.2s",
    fontFamily: "'DM Sans', sans-serif",
  },
  speakBtnActive: {
    background: "rgba(0,212,170,0.12)",
    border: "1px solid rgba(0,212,170,0.35)",
    color: "var(--accent3)",
  },

  // ── Sound wave animation ──────────────────────────────────
  waveWrap: {
    display: "flex", alignItems: "center", gap: "2px", height: "14px",
  },
  wave: {
    display: "inline-block",
    width: "3px",
    height: "10px",
    background: "var(--accent3)",
    borderRadius: "2px",
    animation: "soundWave 0.6s ease-in-out infinite alternate",
  },

  chartWrap: { padding: "16px 8px 8px" },

  // ── Explanation box ───────────────────────────────────────
  explanationBox: {
    margin: "0 14px 14px",
    padding: "14px",
    background: "rgba(79,142,247,0.06)",
    border: "1px solid rgba(79,142,247,0.18)",
    borderRadius: "12px",
  },
  explanationHeader: {
    display: "flex", alignItems: "center", gap: "8px",
    marginBottom: "8px",
  },
  explanationDot: {
    width: "8px", height: "8px", borderRadius: "50%",
    background: "var(--accent)", flexShrink: 0,
    animation: "pulse 1.5s infinite",
  },
  explanationLabel: {
    fontSize: "11px", fontWeight: 700,
    color: "var(--accent)",
    textTransform: "uppercase", letterSpacing: "0.07em",
    flex: 1,
  },
  closeExplanation: {
    background: "none", border: "none",
    color: "var(--text3)", cursor: "pointer",
    fontSize: "13px", padding: "0 2px",
    lineHeight: 1,
  },
  explanationText: {
    fontSize: "13px", color: "var(--text)",
    lineHeight: 1.75,
  },
};
